const repos = ($env.GITHUB_REPOS || '').split(',').map(r => r.trim()).filter(Boolean);
if (repos.length === 0) return [];
return repos.map(repo => ({ json: { repo } }));

const https = require('https');
const githubToken = $env.GITHUB_TOKEN;
if (!githubToken) throw new Error('GITHUB_TOKEN が設定されていません');

function githubGet(path) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.github.com',
      path: path,
      method: 'GET',
      headers: {
        'Authorization': 'token ' + githubToken,
        'Accept': 'application/vnd.github.v3+json',
        'User-Agent': 'claude-pr-review'
      }
    }, (res) => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch(e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

const results = [];
for (const item of $input.all()) {
  const repo = item.json.repo;
  try {
    const prs = await githubGet('/repos/' + repo + '/pulls?state=open&sort=updated&direction=desc&per_page=100');
    if (Array.isArray(prs)) {
      for (const pr of prs) {
        results.push({ json: pr });
      }
    }
  } catch (e) {
    // APIエラー: スキップ（Filter で無視される）
  }
}
if (results.length === 0) results.push({ json: {} });
return results;

// Draft除外 + レビュアーフィルタ + 重複防止 + tracked管理
const staticData = $getWorkflowStaticData('global');
const reviewed = staticData.reviewed || {};
const tracked = staticData.tracked || {};
const newPRs = [];
const inProgress = staticData._inProgress || {};

// 連続失敗3回でレビュー一時停止（トークン切れ等の全体障害対策）
const consecutiveFailures = staticData._consecutiveFailures || 0;
if (consecutiveFailures >= 3) {
  // 2.5時間経過で自動復帰
  const pausedAt = staticData._pausedAt || 0;
  if (Date.now() - pausedAt < 2.5 * 60 * 60 * 1000) return [];
  staticData._consecutiveFailures = 0;
  delete staticData._pausedAt;
}

const targetReviewers = ($env.GITHUB_REVIEWERS || '').split(',').map(r => r.trim()).filter(Boolean);
const targetTeams = ($env.GITHUB_TEAMS || '').split(',').map(t => t.trim()).filter(Boolean);

// #4対策: 今回のポーリングで見えたPRキーを記録
const seenKeys = new Set();
// #12対策: 正常にAPIレスポンスを得たリポジトリを記録
const successRepos = new Set();

for (const item of $input.all()) {
  const prs = Array.isArray(item.json) ? item.json : [item.json];

  for (const pr of prs) {
    if (!pr.number || !pr.head || !pr.base) continue;

    const key = pr.base.repo.full_name + '#' + pr.number;
    seenKeys.add(key);
    successRepos.add(pr.base.repo.full_name);

    if (pr.draft) continue;

    const headSha = pr.head.sha;
    const reviewers = (pr.requested_reviewers || []).map(r => r.login);
    const teams = (pr.requested_teams || []).map(t => t.slug);
    const noFilter = targetReviewers.length === 0 && targetTeams.length === 0;
    const matchUser = targetReviewers.some(t => reviewers.includes(t));
    const matchTeam = targetTeams.some(t => teams.includes(t));
    const isAuthor = targetReviewers.includes(pr.user.login);
    const isTracked = tracked[key] === true;

    if (!noFilter && !matchUser && !matchTeam && !isAuthor && !isTracked) continue;
    if (matchUser || matchTeam || isAuthor) tracked[key] = true;
    // reviewed: sha文字列 or {sha,ts}オブジェクト両対応
    const rev = reviewed[key];
    const revSha = (rev && typeof rev === 'object') ? rev.sha : rev;
    // 同じSHAならスキップ（失敗リトライ中で上限未満の場合は通過）
    if (revSha === headSha) {
      if (!(rev && rev.failed && (rev.retryCount || 0) < 3)) continue;
    }

    // レビュー実行中のPRはスキップ（flock解放〜reviewed記録の隙間対策）
    if (inProgress[key]) continue;

    newPRs.push({ json: {
      number: pr.number, title: pr.title, body: pr.body || '',
      head_ref: pr.head.ref, base_ref: pr.base.ref,
      head_sha: headSha, repo_name: pr.base.repo.name,
      repo_full_name: pr.base.repo.full_name,
      html_url: pr.html_url, user: pr.user.login,
      _key: key
    }});
  }
}

// #4 + #12対策: tracked/reviewed からクローズ済みPRを削除
// ただし、正常にAPIレスポンスを得たリポのPRのみ対象
// APIエラーのリポのPRは消さない（再レビュー暴走を防止）
for (const key of Object.keys(tracked)) {
  const repoName = key.split('#')[0];
  if (successRepos.has(repoName) && !seenKeys.has(key)) {
    delete tracked[key];
    delete reviewed[key];
  }
}
// reviewed にのみ存在するキーもクリーンアップ
for (const key of Object.keys(reviewed)) {
  if (tracked[key] !== undefined) continue; // tracked 側で処理済み
  const repoName = key.split('#')[0];
  if (successRepos.has(repoName) && !seenKeys.has(key)) {
    delete reviewed[key];
  }
}

// 30分以上前の inProgress を解除（レビューが異常終了した場合の救済）
const now = Date.now();
for (const k of Object.keys(inProgress)) {
  if (now - inProgress[k] > 30 * 60 * 1000) delete inProgress[k];
}
staticData.reviewed = reviewed;
staticData.tracked = tracked;
if (newPRs.length === 0) return [];
const picked = newPRs[0];
inProgress[picked.json._key] = Date.now();
staticData._inProgress = inProgress;
return [picked];

// #1対策: base64エンコードでシェルインジェクション防止
const pr = $input.first().json;
const payload = {
  repo_name: pr.repo_name,
  head_ref: pr.head_ref,
  base_ref: pr.base_ref,
  title: pr.title,
  body: pr.body,
  number: String(pr.number),
  _key: pr._key,
  head_sha: pr.head_sha,
  html_url: pr.html_url,
  user: pr.user
};
const encoded = Buffer.from(JSON.stringify(payload)).toString('base64');
return [{ json: { ...pr, encoded } }];

// Claude Code でレビュー実行（非同期 - ワーカーブロック回避）
const { exec } = require('child_process');
const encoded = $input.first().json.encoded;

return new Promise((resolve) => {
  const child = exec(
    `docker exec claude-review-runner bash /scripts/review.sh "${encoded}"`,
    { timeout: 960000, maxBuffer: 10 * 1024 * 1024, encoding: 'utf-8' },
    (error, stdout, stderr) => {
      if (error) {
        resolve([{ json: { stdout: stdout || error.message, exitCode: error.code || 1 } }]);
      } else {
        resolve([{ json: { stdout: stdout, exitCode: 0 } }]);
      }
    }
  );
});

// レビュー成功時のみ reviewed にマーク
const staticData = $getWorkflowStaticData('global');
const reviewed = staticData.reviewed || {};
const rawInput = $input.first().json;
const rawStdout = (rawInput.stdout || '').trim();
const exitCode = rawInput.exitCode;

// review.sh がクラッシュした場合（exitCode !== 0 かつ stdout が空/JSON以外）
if (exitCode !== 0 && !rawStdout.includes('{')) {
  const pr = $('Filter').item.json;
  const slackChannel = $env.SLACK_CHANNEL || '#code-review';
  const mentionIds = ($env.SLACK_MENTION || '').split(',').map(s => s.trim()).filter(Boolean);
  const mention = mentionIds.length > 0 ? mentionIds.map(id => '<@' + id + '>').join(' ') + '\n' : '';
  const isReReview = !!reviewed[pr._key];
  // クラッシュもreviewedに記録（retryCount上限で打ち切り）
  const prevCrash = reviewed[pr._key];
  const crashRetry = (prevCrash && prevCrash.failed && prevCrash.sha === pr.head_sha) ? (prevCrash.retryCount || 0) + 1 : 1;
  reviewed[pr._key] = { sha: pr.head_sha, ts: Date.now(), failed: true, retryCount: crashRetry };
  staticData.reviewed = reviewed;
  // inProgress 解除
  const inProgress = staticData._inProgress || {};
  delete inProgress[pr._key];
  staticData._inProgress = inProgress;
  // 連続失敗カウンター更新
  staticData._consecutiveFailures = (staticData._consecutiveFailures || 0) + 1;
  if (staticData._consecutiveFailures >= 3) staticData._pausedAt = Date.now();
  const crashRetryLabel = crashRetry >= 3 ? '（最終リトライ — 以降スキップ）' : '（リトライ ' + crashRetry + '/3）';
  return [{ json: {
    skip: false, isError: true, isReReview,
    parentText: mention + '❌ PR #' + pr.number + ' ' + pr.title + '\n📦 ' + pr.repo_name + '  レビュー失敗（クラッシュ）' + crashRetryLabel,
    linkMsg: '🔗 ' + pr.html_url + '\n👤 ' + pr.user + '  📦 ' + pr.repo_name + '  🔀 `' + pr.head_ref + '` → `' + pr.base_ref + '`\n```git checkout ' + pr.head_ref + '```\nエラー: ' + (rawStdout.substring(0, 200) || 'プロセス異常終了 (exit ' + exitCode + ')'),
    issueMessages: [], goodMsg: '', manualMsg: '',
    pr: pr, slackChannel: slackChannel
  }}];
}
const pr = $('Filter').item.json;
const slackChannel = $env.SLACK_CHANNEL || '#code-review';
const mentionIds = ($env.SLACK_MENTION || '').split(',').map(s => s.trim()).filter(Boolean);
const mention = mentionIds.length > 0 ? mentionIds.map(id => '<@' + id + '>').join(' ') + '\n' : '';

let review;
let parseSuccess = false;
let debugInfo = '';

// stdoutからJSON部分を抽出（git出力等のプレフィックスを除去）
function extractJson(text) {
  try { return JSON.parse(text); } catch(_) {}
  const first = text.indexOf('{');
  const last = text.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try { return JSON.parse(text.substring(first, last + 1)); } catch(_) {}
  }
  return null;
}

try {
  const parsed = extractJson(rawStdout);
  if (!parsed) {
    debugInfo = 'JSON extraction failed | stdout first 300 chars: ' + rawStdout.substring(0, 300);
    throw new Error(debugInfo);
  }

  // review.sh がエラーを返した場合
  if (parsed.failed) {
    if (parsed.concurrent) return [];
    const isReReview = !!reviewed[pr._key];
    const prevRetry = (reviewed[pr._key] && reviewed[pr._key].failed && reviewed[pr._key].sha === pr.head_sha) ? (reviewed[pr._key].retryCount || 0) : 0;
    const retryCount = prevRetry + 1;
    reviewed[pr._key] = { sha: pr.head_sha, ts: Date.now(), failed: true, retryCount };
    staticData.reviewed = reviewed;
// レビュー完了: inProgress マーカーを解除
const inProgress = staticData._inProgress || {};
delete inProgress[pr._key];
staticData._inProgress = inProgress;
  // 連続失敗カウンター更新
  staticData._consecutiveFailures = (staticData._consecutiveFailures || 0) + 1;
  if (staticData._consecutiveFailures >= 3) staticData._pausedAt = Date.now();
    const retryLabel = retryCount >= 3 ? '（最終リトライ — 以降スキップ）' : '（リトライ ' + retryCount + '/3）';
    return [{ json: {
      skip: false, isError: true, isReReview,
      parentText: mention + '❌ PR #' + pr.number + ' ' + pr.title + '\n📦 ' + pr.repo_name + '  レビュー失敗 ' + retryLabel,
      linkMsg: '🔗 ' + pr.html_url + '\n👤 ' + pr.user + '  📦 ' + pr.repo_name + '  🔀 `' + pr.head_ref + '` → `' + pr.base_ref + '`\n```git checkout ' + pr.head_ref + '```\nエラー: ' + (parsed.error || '不明なエラー'),
      issueMessages: [], goodMsg: '', manualMsg: '',
      pr: pr, slackChannel: slackChannel
    }}];
  }

  // Case 1: review.sh が直接レビューJSONを返した場合（summary があるか）
  if (parsed.summary !== undefined) {
    review = parsed;
    parseSuccess = true;
  }
  // Case 2: Claude ラッパー JSON（{"type":"result","result":"..."}）の場合
  else if (parsed.result) {
    let resultText = parsed.result;
    // ```json ... ``` ブロックを除去
    resultText = resultText.replace(/```json\s*/g, '').replace(/```\s*/g, '');
    const inner = extractJson(resultText);
    if (inner && (inner.summary !== undefined || inner.issues !== undefined)) {
      review = inner;
      parseSuccess = true;
    }
  }

  if (!parseSuccess) {
    const text = parsed.result || parsed.summary || rawStdout;
    review = { summary: text, score: '?', issues: [] };
    if (text && text.length > 10) parseSuccess = true;
  }
} catch (e) {
  review = { summary: 'レビュー結果のパースに失敗しました。' + (debugInfo || e.message), score: '?', issues: [] };
  parseSuccess = false;
}

// 再レビュー判定（reviewed にセットする前に判定）
const isReReview = !!reviewed[pr._key];

// パース成功時のみ reviewed にマーク
let retryCount = 0;
if (parseSuccess) {
  reviewed[pr._key] = { sha: pr.head_sha, ts: Date.now() };
  staticData._consecutiveFailures = 0;
  delete staticData._pausedAt;
} else {
  const prev = reviewed[pr._key];
  const prevRetry = (prev && prev.failed && prev.sha === pr.head_sha) ? (prev.retryCount || 0) : 0;
  retryCount = prevRetry + 1;
  reviewed[pr._key] = { sha: pr.head_sha, ts: Date.now(), failed: true, retryCount };
  staticData._consecutiveFailures = (staticData._consecutiveFailures || 0) + 1;
  if (staticData._consecutiveFailures >= 3) staticData._pausedAt = Date.now();
}
staticData.reviewed = reviewed;
// レビュー完了: inProgress マーカーを解除
const inProgress = staticData._inProgress || {};
delete inProgress[pr._key];
staticData._inProgress = inProgress;

const critical = (review.issues || []).filter(i => i.severity === 'Critical');
const warning = (review.issues || []).filter(i => i.severity === 'Warning');

const counts = [];
if (critical.length) counts.push('🔴' + critical.length);
if (warning.length) counts.push('🟡' + warning.length);
const countStr = counts.length > 0 ? counts.join(' ') : '✅ 問題なし';

const retryLabel = retryCount > 0 ? (retryCount >= 3 ? ' （最終リトライ — 以降スキップ）' : ' （リトライ ' + retryCount + '/3）') : '';
const parentText = mention + '🔍 PR #' + pr.number + ' ' + pr.title + '\n📦 ' + pr.repo_name + '  📊 Score: ' + (review.score || '?') + '  ' + countStr + retryLabel;

// 概要: summary + change_impact を統合
let overview = review.summary || '';
if (review.change_impact && review.change_impact.description) {
  overview += '\n\n📋 *変更の影響*\n' + review.change_impact.description;
  if (review.change_impact.behavioral_changes && review.change_impact.behavioral_changes.length > 0) {
    overview += '\n' + review.change_impact.behavioral_changes.map(c => '• ' + c.before + ' → ' + c.after + (c.intentional ? '' : ' ⚠️意図しない変更')).join('\n');
  }
}
const linkMsg = '🔗 ' + pr.html_url + '\n👤 ' + pr.user + '  📦 ' + pr.repo_name + '  🔀 `' + pr.head_ref + '` → `' + pr.base_ref + '`\n```git checkout ' + pr.head_ref + '```\n\n📝 *概要*\n' + overview;

const issueMessages = (review.issues || []).map(issue => {
  const icon = issue.severity === 'Critical' ? '🔴' : '🟡';
  return icon + ' *' + issue.severity + ' — ' + issue.category + '*\n📄 `' + issue.file + ':' + issue.line + '`\n' + issue.description + '\n💡 `' + issue.suggestion + '`';
});

let goodMsg = '';
if (review.good_points && review.good_points.length > 0) {
  goodMsg = '✅ *良い点*\n' + review.good_points.map(p => '• ' + p).join('\n');
}

let manualMsg = '';
if (review.needs_manual_review) {
  manualMsg = '⚠️ *手動レビュー推奨*\n' + (review.manual_review_reason || '');
}

return [{ json: { skip: false, isError: false, isReReview, parentText, linkMsg, issueMessages, goodMsg, manualMsg, pr, slackChannel } }];

const https = require('https');
const slackToken = $env.SLACK_BOT_TOKEN || '';

function slackGet(method, params) {
  return new Promise((resolve, reject) => {
    const query = Object.entries(params).map(([k,v]) => k + '=' + encodeURIComponent(v)).join('&');
    const req = https.request({
      hostname: 'slack.com',
      path: '/api/' + method + '?' + query,
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + slackToken }
    }, (res) => {
      let body = '';
      res.on('data', chunk => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch(e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

const data = $input.first().json;
let hasThread = false;
let threadTs = '';

if (slackToken) {
  try {
    const staticData = $getWorkflowStaticData('global');
    let channelId = '';
    if (staticData._slackChannelId && staticData._slackChannelRaw === data.slackChannel) {
      channelId = staticData._slackChannelId;
    } else {
      const ch = data.slackChannel.replace(/^#/, '');
      const infoResult = await slackGet('conversations.info', { channel: ch });
      if (infoResult.ok) {
        channelId = ch;
      } else {
        const listResult = await slackGet('conversations.list', { limit: '1000', exclude_archived: 'true', types: 'public_channel,private_channel' });
        if (listResult.ok) {
          const found = (listResult.channels || []).find(c => c.name === ch);
          if (found) channelId = found.id;
        }
      }
      if (channelId) {
        staticData._slackChannelId = channelId;
        staticData._slackChannelRaw = data.slackChannel;
      }
    }

    if (channelId) {
      const result = await slackGet('conversations.history', { channel: channelId, limit: '50' });
      if (result.ok && result.messages) {
        const prNum = String(data.pr.number);
        const repoName = data.pr.repo_name;
        const parent = result.messages.find(m =>
          m.bot_id && m.text &&
          m.text.includes('PR #' + prNum) && m.text.includes(repoName) &&
          !m.text.match(new RegExp('PR #' + prNum + '[0-9]'))
        );
        if (parent) {
          threadTs = parent.ts;
          hasThread = true;
        }
      }
    }
  } catch (e) { /* Slack API error */ }
}

return [{ json: { ...data, hasThread, threadTs } }];

const https = require('https');
const data = $input.first().json;
const slackToken = $env.SLACK_BOT_TOKEN;

if (!slackToken) {
  throw new Error('SLACK_BOT_TOKEN が .env に設定されていません');
}

const staticData = $getWorkflowStaticData('global');
const channelId = staticData._slackChannelId || data.slackChannel.replace(/^#/, '');

// --- Slack API ヘルパー ---
function slackPost(method, bodyObj) {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify(bodyObj);
    const req = https.request({
      hostname: 'slack.com',
      path: '/api/' + method,
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + slackToken,
        'Content-Type': 'application/json; charset=utf-8',
        'Content-Length': Buffer.byteLength(payload)
      }
    }, (res) => {
      let respBody = '';
      res.on('data', chunk => respBody += chunk);
      res.on('end', () => {
        try {
          const result = JSON.parse(respBody);
          if (result.ok) resolve(result);
          else reject(new Error(result.error || 'unknown'));
        } catch(e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(payload);
    req.end();
  });
}

// files.uploadV2（3ステップ）でファイルアップロード
async function uploadFile(channel, threadTs, filename, content, title) {
  const contentBuf = Buffer.from(content, 'utf-8');

  // Step 1: アップロードURL取得
  const step1 = await new Promise((resolve, reject) => {
    const payload = JSON.stringify({ filename, length: contentBuf.length });
    const req = https.request({
      hostname: 'slack.com',
      path: '/api/files.getUploadURLExternal',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + slackToken,
        'Content-Type': 'application/json; charset=utf-8',
        'Content-Length': Buffer.byteLength(payload)
      }
    }, (res) => {
      let respBody = '';
      res.on('data', chunk => respBody += chunk);
      res.on('end', () => {
        try {
          const result = JSON.parse(respBody);
          if (result.ok) resolve(result);
          else reject(new Error('getUploadURL: ' + (result.error || 'unknown')));
        } catch(e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(payload);
    req.end();
  });

  // Step 2: ファイル内容をアップロード
  const uploadUrl = new URL(step1.upload_url);
  await new Promise((resolve, reject) => {
    const req = https.request({
      hostname: uploadUrl.hostname,
      path: uploadUrl.pathname + uploadUrl.search,
      method: 'POST',
      headers: {
        'Content-Type': 'application/octet-stream',
        'Content-Length': contentBuf.length
      }
    }, (res) => {
      let respBody = '';
      res.on('data', chunk => respBody += chunk);
      res.on('end', () => resolve(respBody));
    });
    req.on('error', reject);
    req.write(contentBuf);
    req.end();
  });

  // Step 3: アップロード完了 + チャンネル/スレッドに共有
  const step3Body = {
    files: [{ id: step1.file_id, title: title }],
    channel_id: channel
  };
  if (threadTs) step3Body.thread_ts = threadTs;
  await new Promise((resolve, reject) => {
    const payload = JSON.stringify(step3Body);
    const req = https.request({
      hostname: 'slack.com',
      path: '/api/files.completeUploadExternal',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + slackToken,
        'Content-Type': 'application/json; charset=utf-8',
        'Content-Length': Buffer.byteLength(payload)
      }
    }, (res) => {
      let respBody = '';
      res.on('data', chunk => respBody += chunk);
      res.on('end', () => {
        try {
          const result = JSON.parse(respBody);
          if (result.ok) resolve(result);
          else reject(new Error('completeUpload: ' + (result.error || 'unknown')));
        } catch(e) { reject(e); }
      });
    });
    req.on('error', reject);
    req.write(payload);
    req.end();
  });
}

async function postWithRetry(method, bodyObj) {
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      return await slackPost(method, bodyObj);
    } catch (e) {
      if (attempt === 2) throw new Error('Slack投稿失敗（3回リトライ後）: ' + e.message);
      await new Promise(r => setTimeout(r, 1000 * (attempt + 1)));
    }
  }
}

async function postMsg(channel, text, threadTs) {
  const body = { channel, text };
  if (threadTs) body.thread_ts = threadTs;
  const result = await postWithRetry('chat.postMessage', body);
  return result.ts;
}

// --- Markdown 生成 ---
function buildMarkdown() {
  const pr = data.pr;
  const lines = [];
  lines.push('# PR #' + pr.number + ' ' + (pr.title || ''));
  lines.push('');
  lines.push('| 項目 | 値 |');
  lines.push('|---|---|');
  lines.push('| リポジトリ | ' + (pr.repo_name || '') + ' |');
  lines.push('| 作成者 | ' + (pr.user || '') + ' |');
  lines.push('| ブランチ | `' + (pr.head_ref || '') + '` → `' + (pr.base_ref || '') + '` |');
  lines.push('| URL | ' + (pr.html_url || '') + ' |');
  lines.push('');

  // 概要（linkMsg からコマンド部分を除いた概要テキストを抽出）
  const overviewMatch = (data.linkMsg || '').split('📝 *概要*\n');
  if (overviewMatch.length > 1) {
    lines.push('## 概要');
    lines.push('');
    lines.push(overviewMatch[1]);
    lines.push('');
  }

  // Issues
  if (data.issueMessages && data.issueMessages.length > 0) {
    lines.push('## 指摘事項');
    lines.push('');
    for (const msg of data.issueMessages) {
      // Slack mrkdwn → Markdown 変換
      const md = msg
        .replace(/^\u{1F534} \*Critical/, '### 🔴 Critical')
        .replace(/^\u{1F7E1} \*Warning/, '### 🟡 Warning')
        .replace(/\*$/, '')
        .replace(/\n📄 `([^`]+)`/, '\n**ファイル:** `$1`')
        .replace(/\n💡 `([^`]+)`/, '\n\n**修正案:** `$1`');
      lines.push(md);
      lines.push('');
    }
  }

  // 良い点
  if (data.goodMsg) {
    lines.push('## 良い点');
    lines.push('');
    const goodContent = data.goodMsg.replace('✅ *良い点*\n', '');
    lines.push(goodContent);
    lines.push('');
  }

  // 手動レビュー
  if (data.manualMsg) {
    lines.push('## 手動レビュー推奨');
    lines.push('');
    const manualContent = data.manualMsg.replace('⚠️ *手動レビュー推奨*\n', '');
    lines.push(manualContent);
    lines.push('');
  }

  lines.push('---');
  lines.push('*Generated by Claude Code PR Review*');
  return lines.join('\n');
}

// --- メイン処理 ---
// スレッド返信用のメッセージ一覧
const threadMessages = [];
threadMessages.push(data.linkMsg);
for (const msg of data.issueMessages) {
  threadMessages.push(msg);
}
if (data.goodMsg) threadMessages.push(data.goodMsg);
if (data.manualMsg) threadMessages.push(data.manualMsg);

let parentTs = data.threadTs;

try {
  if (data.hasThread && parentTs) {
    // 既存スレッドに追記
    const header = data.isReReview
      ? '\u{1F504} *再レビュー*\n' + data.parentText
      : data.parentText;
    await postMsg(channelId, header, parentTs);
    for (const msg of threadMessages) {
      await postMsg(channelId, msg, parentTs);
    }
  } else {
    // 新規親スレッド作成
    const parentText = data.isReReview
      ? '\u{1F504} *再レビュー*\n' + data.parentText
      : data.parentText;
    parentTs = await postMsg(channelId, parentText, null);
    for (const msg of threadMessages) {
      await postMsg(channelId, msg, parentTs);
    }
  }

  // Markdown ファイルをスレッドに添付（エラー時はスキップ）
  if (!data.isError) {
    try {
      const md = buildMarkdown();
      const filename = 'review_PR' + data.pr.number + '.md';
      await uploadFile(channelId, parentTs, filename, md, 'PR #' + data.pr.number + ' レビュー詳細');
    } catch (e) {
      // ファイルアップロード失敗は無視（メッセージは投稿済み）
    }
  }
} catch (e) {
  throw new Error('Slack投稿中にエラー: ' + e.message + '（一部メッセージは投稿済みの可能性があります）');
}

return [{ json: { success: true, parentTs, channel: channelId } }];
